// Gap % = (today's first open - prev session's last close) / prev close
function computeGap(bars, todayDate) {
  const prevBars  = bars.filter(b => !b.date.startsWith(todayDate));
  const todayBars = bars.filter(b =>  b.date.startsWith(todayDate));
  if (prevBars.length === 0 || todayBars.length === 0) return null;
  const prevClose = prevBars[0].close;           // newest-first → [0] = last bar of prev session
  const todayOpen = todayBars.at(-1)?.open;      // oldest today bar = 9:30 open
  if (!prevClose || !todayOpen) return null;
  return (todayOpen - prevClose) / prevClose * 100;
}

// VWAP of the ORB window (9:30–9:34) using typical price × volume
function computeORBVWAP(bars, todayDate) {
  const orbBars = bars.filter(b => {
    if (!b.date.startsWith(todayDate)) return false;
    const tp = b.date.split(' ')[1] ?? '';
    const [h, m] = tp.split(':').map(Number);
    return h === 9 && m >= 30 && m <= 34;
  });
  let cumPV = 0, cumVol = 0;
  for (const b of orbBars) {
    const typical = ((b.high ?? b.close) + (b.low ?? b.close) + (b.close ?? 0)) / 3;
    const vol = b.volume ?? 0;
    cumPV += typical * vol;
    cumVol += vol;
  }
