/**
 * backtest-orb-eod.mjs — EOD proxy backtest for the ORB + Entropy strategy.
 *
 * For each symbol+direction from today's ORB screen (or --symbols flag),
 * fetches historical daily OHLCV and simulates ORB-proxy trades:
 *   Entry = day open, stop = entry ± (stopAtr × ATR14), target = entry ± 2R
 *   Income layer (50%): exit at 2R if hit (inferred from high/low), else close
 *   Edge layer (50%): always exit at close
 *   If stop is hit, full -1R regardless of whether target also triggered (conservative)
 *   ATR is computed with no lookahead: atrs[i-1] gates simulation day i
 */

import { readFileSync, mkdirSync, existsSync } from 'fs';
import { join } from 'path';
import { fetchDailyPricesFull } from '../lib/fmp-client.mjs';
import { mapConcurrent } from '../lib/fetcher.mjs';
import { buildNote, buildTable, writeNote, today, dateStampedFilename } from '../lib/markdown.mjs';
import { getPullsDir } from '../lib/config.mjs';

const DEFAULTS = { days: 120, stopAtr: 0.10, gapMin: 0.001, concurrency: 5, atrPeriod: 14 };

// ── Running ATR (Wilder's EMA) ────────────────────────────────────────────────
// Returns array aligned with series; atrs[i] incorporates data through series[i].
// Use atrs[i-1] on simulation day i to avoid lookahead bias.

function buildRunningATR(series, period = 14) {
  const atrs = new Array(series.length).fill(null);
  const trs  = [];
  for (let i = 1; i < series.length; i++) {
    const c = series[i], p = series[i - 1];
    trs.push(Math.max(
      Number(c.high) - Number(c.low),
      Math.abs(Number(c.high) - Number(p.close)),
      Math.abs(Number(c.low)  - Number(p.close)),
    ));
    const k = trs.length;
    if (k === period)    atrs[i] = trs.reduce((s, v) => s + v, 0) / period;
    else if (k > period) atrs[i] = (atrs[i - 1] * (period - 1) + trs[k - 1]) / period;
  }
  return atrs;
}

// ── Trade Sheet parser ────────────────────────────────────────────────────────

function parseTradeSheet(markdown) {
  const lines = markdown.split('\n');
  let inSection = false, headers = null;
  const rows = [];

  for (const line of lines) {
    if (line.startsWith('## ')) { inSection = line.includes('Trade Sheet'); headers = null; continue; }
    if (!inSection || !line.startsWith('|')) continue;
    const cells = line.split('|').slice(1, -1).map(c => c.trim());
    if (!headers) { headers = cells; continue; }
    if (cells.every(c => /^[-: ]*$/.test(c))) continue;
    rows.push(Object.fromEntries(headers.map((h, i) => [h, cells[i] ?? ''])));
  }

  return rows.map(r => ({
    symbol:    (r['Ticker'] || '').replace(/\[\[|\]\]/g, '').trim(),
    direction: (r['Direction'] || '').toUpperCase().trim(),
  })).filter(r => r.symbol && ['LONG', 'SHORT'].includes(r.direction));
}

// ── Single-day simulation ─────────────────────────────────────────────────────

function simulateDay({ bar, prevClose, atr, direction, stopAtrFraction, gapMin }) {
  if (!atr || !bar || !Number.isFinite(prevClose)) return null;
  const o = Number(bar.open), h = Number(bar.high), l = Number(bar.low), c = Number(bar.close);
  if (![o, h, l, c].every(Number.isFinite)) return null;

  const gapPct = (o - prevClose) / prevClose;
  if (direction === 'LONG'  && gapPct < gapMin)  return null;
  if (direction === 'SHORT' && gapPct > -gapMin) return null;

  const stopDist = stopAtrFraction * atr;
  const stop     = direction === 'LONG' ? o - stopDist : o + stopDist;
  const r        = Math.abs(o - stop);
  if (r === 0) return null;
  const target2r = direction === 'LONG' ? o + 2 * r : o - 2 * r;
  const sign     = direction === 'LONG' ? 1 : -1;

  const stopHit   = direction === 'LONG' ? l <= stop    : h >= stop;
  const targetHit = direction === 'LONG' ? h >= target2r : l <= target2r;

  if (stopHit) return { date: bar.date, outcome: 'stopped', rMultiple: -1, gapPct };

  const incomeR = targetHit ? 2 : ((c - o) * sign) / r;
  const edgeR   = ((c - o) * sign) / r;

  return { date: bar.date, outcome: targetHit ? 'target' : 'held', rMultiple: 0.5 * incomeR + 0.5 * edgeR, incomeR, edgeR, gapPct };
}

// ── Per-symbol backtest ───────────────────────────────────────────────────────

async function backtestSymbol(symbol, direction, fromDate, config) {
  const raw = await fetchDailyPricesFull(symbol, { from: fromDate });
  if (!raw || raw.length < config.atrPeriod + 2) return null;

  const series = [...raw].sort((a, b) => String(a.date).localeCompare(String(b.date)));
  const atrs   = buildRunningATR(series, config.atrPeriod);
  const trades = [];

  for (let i = config.atrPeriod + 1; i < series.length; i++) {
    const result = simulateDay({
      bar:             series[i],
      prevClose:       Number(series[i - 1].close),
      atr:             atrs[i - 1],   // prior bar ATR — no lookahead
      direction,
      stopAtrFraction: config.stopAtr,
      gapMin:          config.gapMin,
    });
    if (result) trades.push(result);
  }

  if (!trades.length) return { symbol, direction, trades: [], stats: null };

  const rs   = trades.map(t => t.rMultiple);
  const wins = rs.filter(r => r > 0).length;
  const avgR = rs.reduce((s, v) => s + v, 0) / rs.length;
  const stdR = Math.sqrt(rs.map(r => (r - avgR) ** 2).reduce((s, v) => s + v, 0) / rs.length);
  let maxCL = 0, curCL = 0;
  for (const r of rs) { curCL = r < 0 ? curCL + 1 : 0; maxCL = Math.max(maxCL, curCL); }

  return {
    symbol, direction, trades,
    stats: {
      n: trades.length, wins, winRate: wins / trades.length,
      avgR, totalR: rs.reduce((s, v) => s + v, 0), stdR,
      sharpe: stdR > 0 ? avgR / stdR : 0,
      maxConsecLoss: maxCL,
      targets: trades.filter(t => t.outcome === 'target').length,
      stopped: trades.filter(t => t.outcome === 'stopped').length,
    },
  };
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function daysAgo(n) {
  const d = new Date(); d.setDate(d.getDate() - n); return d.toISOString().slice(0, 10);
}
function fmt(v, d = 2)  { return Number.isFinite(v) ? v.toFixed(d) : '--'; }
function fmtPct(v)       { return Number.isFinite(v) ? `${(v * 100).toFixed(1)}%` : '--'; }

// ── Main ──────────────────────────────────────────────────────────────────────

export async function pull(flags = {}) {
  const days    = Number(flags.days        ?? DEFAULTS.days);
  const stopAtr = Number(flags['stop-atr'] ?? DEFAULTS.stopAtr);
  const gapMin  = Number(flags['gap-min']  ?? DEFAULTS.gapMin);
  const config  = { days, stopAtr, gapMin, atrPeriod: DEFAULTS.atrPeriod };

  let pairs = [];

  if (flags.symbols || flags.symbol) {
    pairs = String(flags.symbols ?? flags.symbol).split(',').map(s => {
      const [sym, dir = 'LONG'] = s.trim().toUpperCase().split(':');
      return { symbol: sym, direction: dir };
    }).filter(p => p.symbol && ['LONG', 'SHORT'].includes(p.direction));
  } else {
    const screenPath = join(getPullsDir(), 'Market', `${today()}_ORB_Entropy_Screen.md`);
    if (!existsSync(screenPath)) {
      console.error(`Backtest ORB EOD: no ORB screen for today. Run orb-entropy first, or pass --symbols TICKER:DIR,...`);
      return;
    }
    pairs = parseTradeSheet(readFileSync(screenPath, 'utf8'));
    console.log(`Backtest ORB EOD: read ${pairs.length} signals from today's screen`);
  }

  if (!pairs.length) { console.log('Backtest ORB EOD: no signals to process.'); return; }

  const fromDate = daysAgo(days + 25); // extra buffer for ATR warmup
  console.log(`Backtest ORB EOD: simulating ${pairs.length} symbol(s) over ${days} days from ${fromDate}...`);

  const results = (await mapConcurrent(pairs, DEFAULTS.concurrency, ({ symbol, direction }) =>
    backtestSymbol(symbol, direction, fromDate, config)
  )).filter(r => r?.stats);

  console.log(`  ${results.length} of ${pairs.length} symbols had sufficient data`);

  const allTrades  = results.flatMap(r => r.trades);
  const allR       = allTrades.map(t => t.rMultiple);
  const aggWins    = allR.filter(r => r > 0).length;
  const aggAvgR    = allR.length ? allR.reduce((s, v) => s + v, 0) / allR.length : 0;
  const aggTotalR  = allR.reduce((s, v) => s + v, 0);
  const aggStd     = Math.sqrt(allR.map(r => (r - aggAvgR) ** 2).reduce((s, v) => s + v, 0) / (allR.length || 1));
  const aggSharpe  = aggStd > 0 ? aggAvgR / aggStd : 0;
  const aggWinRate = allR.length ? aggWins / allR.length : 0;

  const summaryRows = [...results]
    .sort((a, b) => b.stats.avgR - a.stats.avgR)
    .map(r => {
      const s = r.stats;
      return [
        `[[${r.symbol}]]`, r.direction, String(s.n),
        fmtPct(s.winRate), fmt(s.avgR, 3), fmt(s.totalR, 2),
        fmt(s.sharpe, 2), String(s.targets), String(s.stopped), String(s.maxConsecLoss),
      ];
    });

  const outDir  = join(getPullsDir(), 'Backtest');
  mkdirSync(outDir, { recursive: true });
  const outPath = join(outDir, dateStampedFilename('ORB_EOD_Backtest'));

  const note = buildNote({
    frontmatter: {
      title:        'ORB EOD Proxy Backtest',
      source:       'FMP Historical OHLCV',
      date_pulled:  today(),
      domain:       'backtest',
      data_type:    'orb_eod_backtest',
      frequency:    'on-demand',
      total_trades: allTrades.length,
      win_rate:     fmtPct(aggWinRate),
      avg_r:        fmt(aggAvgR, 3),
      tags:         ['backtest', 'orb', 'eod', 'equities'],
    },
    sections: [
      {
        heading: 'Parameters',
        content: [
          `- **Lookback**: ${days} calendar days from ${fromDate}`,
          `- **Stop distance**: ${(stopAtr * 100).toFixed(0)}% × ATR14 (Wilder's EMA, no lookahead)`,
          `- **Gap filter**: ≥ ${(gapMin * 100).toFixed(1)}% open gap aligned with direction`,
          `- **Entry**: day open`,
          `- **Income layer (50%)**: 2R target if hit (inferred from daily high/low), else close`,
          `- **Edge layer (50%)**: always close`,
          `- **Stop**: hard stop on intraday low/high breach; stop wins if target also triggered same bar (conservative)`,
        ].join('\n'),
      },
      {
        heading: 'Aggregate Stats',
        content: [
          `- **Total trades**: ${allTrades.length} across ${results.length} symbol(s)`,
          `- **Win rate**: ${fmtPct(aggWinRate)}`,
          `- **Avg R / trade**: ${fmt(aggAvgR, 3)}`,
          `- **Total R**: ${fmt(aggTotalR, 2)}`,
          `- **Sharpe (R-series)**: ${fmt(aggSharpe, 2)}`,
        ].join('\n'),
      },
      {
        heading: 'Per-Symbol Results',
        content: summaryRows.length > 0
          ? buildTable(
              ['Symbol', 'Dir', 'N', 'Win%', 'AvgR', 'TotalR', 'Sharpe', 'Targets', 'Stops', 'MaxConsecLoss'],
              summaryRows,
            )
          : '_No results._',
      },
      {
        heading: 'How to Read',
        content: [
          '- **AvgR > 0**: positive expectancy. > 0.3R per trade is meaningful for a day-trade strategy.',
          '- **Sharpe**: AvgR ÷ StdR across trades. > 0.5 is reasonable; > 1.0 is strong.',
          '- **Targets**: income layer exited at 2R — indicates compressed/trending days.',
          '- **MaxConsecLoss**: worst losing streak — key for sizing and drawdown planning.',
          '- Gap filter applied: only gap-aligned days are simulated (same 0.1% threshold as live strategy).',
          '- EOD proxy — intraday fill quality, slippage, and exact stop execution are not modeled.',
          '- Run daily with `node run.mjs pull backtest-orb-eod` to track rolling edge over time.',
        ].join('\n'),
      },
    ],
  });

  writeNote(outPath, note);
  console.log(`Wrote: ${outPath}`);
  console.log(`  ${allTrades.length} trades | Win%: ${fmtPct(aggWinRate)} | AvgR: ${fmt(aggAvgR, 3)} | Sharpe: ${fmt(aggSharpe, 2)}`);
}

