/**
 * signal-tracker.mjs — Forward signal tracker for ORB strategy signals.
 *
 * --log    : Parse today's ORB screen Trade Sheet and append new signals to the journal.
 * (default): Reconcile — fetch recent closing prices for open positions, mark outcomes,
 *            write a daily Signal Outcomes note.
 *
 * Journal: 05_Data_Pulls/Backtest/signal_journal.csv
 * Columns: date, symbol, direction, entry, stop, target_2r, tier, strategy, outcome, r_multiple, notes
 *
 * Outcome values: open → stopped | target | held | error
 * R convention: income layer (50%) exits at 2R if target hit, else close; edge layer (50%) always close.
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join } from 'path';
import { fetchDailyPrices } from '../lib/fmp-client.mjs';
import { mapConcurrent } from '../lib/fetcher.mjs';
import { buildNote, buildTable, writeNote, today, dateStampedFilename } from '../lib/markdown.mjs';
import { getPullsDir } from '../lib/config.mjs';

const JOURNAL_HEADER = 'date,symbol,direction,entry,stop,target_2r,tier,strategy,outcome,r_multiple,notes';
const CONCURRENCY    = 5;

function journalPath() { return join(getPullsDir(), 'Backtest', 'signal_journal.csv'); }

// ── Trade Sheet parser ────────────────────────────────────────────────────────

function parseTradeSheet(markdown) {
  const lines = markdown.split('\n');
  let inSection = false, headers = null;
  const rows = [];

  for (const line of lines) {
    if (line.startsWith('## ')) { inSection = line.includes('Trade Sheet'); headers = null; continue; }
    if (!inSection || !line.startsWith('|')) continue;
    const cells = line.split('|').slice(1, -1).map(c => c.trim());
    if (!headers) { headers = cells; continue; }
    if (cells.every(c => /^[-: ]*$/.test(c))) continue;
    rows.push(Object.fromEntries(headers.map((h, i) => [h, cells[i] ?? ''])));
  }

  const num = s => parseFloat((s || '').replace(/[$,]/g, ''));
  return rows.map(r => ({
    symbol:    (r['Ticker'] || '').replace(/\[\[|\]\]/g, '').trim(),
    direction: (r['Direction'] || '').toUpperCase().trim(),
    entry:     num(r['Entry']),
    stop:      num(r['Stop']),
    target_2r: num(r['2R Target']),
    tier:      (r['Tier'] || '').trim(),
  })).filter(r => r.symbol && ['LONG', 'SHORT'].includes(r.direction) && Number.isFinite(r.entry));
}

// ── Journal helpers ───────────────────────────────────────────────────────────

function loadJournal() {
  const path = journalPath();
  if (!existsSync(path)) return { header: JOURNAL_HEADER, rows: [] };
  const lines = readFileSync(path, 'utf8').split('\n').filter(l => l.trim());
  const [header, ...dataLines] = lines;
  const cols = header.split(',');
  return {
    header,
    rows: dataLines.map(l => {
      const vals = l.split(',');
      return Object.fromEntries(cols.map((c, i) => [c, vals[i] ?? '']));
    }),
  };
}

function saveJournal({ header, rows }) {
  mkdirSync(join(getPullsDir(), 'Backtest'), { recursive: true });
  const cols    = header.split(',');
  const lines   = rows.map(r => cols.map(c => r[c] ?? '').join(','));
  writeFileSync(journalPath(), [header, ...lines].join('\n') + '\n', 'utf8');
}

// ── Log mode ──────────────────────────────────────────────────────────────────

async function logSignals() {
  const screenPath = join(getPullsDir(), 'Market', `${today()}_ORB_Entropy_Screen.md`);
  if (!existsSync(screenPath)) {
    console.error(`Signal Tracker: no ORB screen for today. Run orb-entropy first.`);
    return;
  }

  const signals = parseTradeSheet(readFileSync(screenPath, 'utf8'));
  const journal = loadJournal();

  // Idempotent: skip signals already logged for today
  const existing = new Set(
    journal.rows.filter(r => r.date === today()).map(r => `${r.symbol}:${r.direction}`)
  );
  const newRows = signals
    .filter(s => !existing.has(`${s.symbol}:${s.direction}`))
    .map(s => ({
      date: today(), symbol: s.symbol, direction: s.direction,
      entry: String(s.entry), stop: String(s.stop), target_2r: String(s.target_2r),
      tier: s.tier, strategy: 'orb-entropy',
      outcome: 'open', r_multiple: '', notes: '',
    }));

  if (!newRows.length) {
    console.log(`Signal Tracker: all ${signals.length} signal(s) already logged for today.`);
    return;
  }

  journal.rows.push(...newRows);
  saveJournal(journal);
  console.log(`Signal Tracker: logged ${newRows.length} new signal(s) (${signals.length - newRows.length} already existed)`);
}

// ── Reconcile mode ────────────────────────────────────────────────────────────

async function reconcileSignals() {
  const journal = loadJournal();
  const open    = journal.rows.filter(r => r.outcome === 'open');

  if (!open.length) { console.log('Signal Tracker: no open positions to reconcile.'); return; }

  const symbols = [...new Set(open.map(r => r.symbol))];
  console.log(`Signal Tracker: reconciling ${open.length} open position(s) across ${symbols.length} symbol(s)...`);

  const priceMap = new Map();
  await mapConcurrent(symbols, CONCURRENCY, async sym => {
    try {
      const bars = await fetchDailyPrices(sym);
      if (bars?.length) priceMap.set(sym, bars[0]); // newest-first → [0] is most recent trading day
    } catch { /* skip symbol */ }
  });

  const resolved = [];

  for (const row of journal.rows) {
    if (row.outcome !== 'open') continue;

    const bar = priceMap.get(row.symbol);
    if (!bar) { row.outcome = 'error'; row.notes = 'price fetch failed'; resolved.push(row); continue; }

    const e    = Number(row.entry), s = Number(row.stop), t = Number(row.target_2r);
    const r    = Math.abs(e - s);
    const dir  = row.direction;
    const high = Number(bar.high), low = Number(bar.low), close = Number(bar.close);

    const stopHit   = dir === 'LONG' ? low  <= s : high >= s;
    const targetHit = dir === 'LONG' ? high >= t : low  <= t;
    const closeR    = dir === 'LONG' ? (close - e) / r : (e - close) / r;

    if (stopHit) {
      row.outcome    = 'stopped';
      row.r_multiple = '-1.000';
    } else if (targetHit) {
      row.outcome    = 'target';
      row.r_multiple = (0.5 * 2 + 0.5 * closeR).toFixed(3);
    } else {
      row.outcome    = 'held';
      row.r_multiple = closeR.toFixed(3);
    }

    row.notes = `${bar.date} close $${Number(close).toFixed(2)}`;
    resolved.push(row);
  }

  saveJournal(journal);
  console.log(`  Marked ${resolved.length} position(s)`);

  const todayStr  = today();
  const totalR    = resolved.reduce((s, p) => s + Number(p.r_multiple || 0), 0);
  const wins      = resolved.filter(p => Number(p.r_multiple) > 0).length;
  const tableRows = resolved.map(p => [
    `[[${p.symbol}]]`, p.direction, p.tier || '--',
    `$${Number(p.entry).toFixed(2)}`,
    `$${Number(p.stop).toFixed(2)}`,
    `$${Number(p.target_2r).toFixed(2)}`,
    p.notes || '--',
    p.outcome,
    p.r_multiple || '--',
  ]);

  const outDir  = join(getPullsDir(), 'Backtest');
  mkdirSync(outDir, { recursive: true });
  const outPath = join(outDir, dateStampedFilename('Signal_Outcomes'));

  const note = buildNote({
    frontmatter: {
      title:       `Signal Outcomes ${todayStr}`,
      source:      'ORB Screen + FMP Closing Prices',
      date_pulled: todayStr,
      domain:      'backtest',
      data_type:   'signal_outcomes',
      frequency:   'daily',
      total_r:     totalR.toFixed(3),
      win_rate:    resolved.length > 0 ? (wins / resolved.length).toFixed(3) : '0',
      tags:        ['backtest', 'signal-tracker', 'orb', 'outcomes'],
    },
    sections: [
      {
        heading: 'Session Summary',
        content: [
          `- **Positions reconciled**: ${resolved.length}`,
          `- **Wins**: ${wins} of ${resolved.length} (${resolved.length ? Math.round(100 * wins / resolved.length) : 0}%)`,
          `- **Total R**: ${totalR.toFixed(3)}`,
          `- **Avg R**: ${resolved.length ? (totalR / resolved.length).toFixed(3) : '--'}`,
        ].join('\n'),
      },
      {
        heading: 'Trade Outcomes',
        content: tableRows.length > 0
          ? buildTable(
              ['Symbol', 'Dir', 'Tier', 'Entry', 'Stop', '2R Target', 'Exit', 'Outcome', 'R Multiple'],
              tableRows,
            )
          : '_No positions._',
      },
      {
        heading: 'How to Read',
        content: [
          '- **R Multiple**: blended income/edge split. 50% income layer exits at 2R if hit, else close; 50% edge layer always closes.',
          '- **target**: income layer hit 2R. R multiple = 0.5 × 2 + 0.5 × closeR.',
          '- **held**: neither stop nor 2R hit; both layers exit at close.',
          '- **stopped**: full -1R. Conservative — stop wins even if close was profitable.',
          '- Run `node run.mjs pull signal-tracker --log` to log today\'s signals after ORB screen runs.',
          '- Run `node run.mjs pull signal-tracker` (no flag) after market close to mark outcomes.',
        ].join('\n'),
      },
    ],
  });

  writeNote(outPath, note);
  console.log(`  Wrote: ${outPath}`);
  console.log(`  Total R: ${totalR.toFixed(3)} | Wins: ${wins}/${resolved.length}`);
}

// ── Main ──────────────────────────────────────────────────────────────────────

export async function pull(flags = {}) {
  if (flags.log) {
    await logSignals();
  } else {
    await reconcileSignals();
  }
}

